log-to-eventhub.expression:
@{
                var department = (string)context.Variables["department"];
                var timestamp = DateTime.UtcNow.ToString("o");
                return new {
                    timestamp = timestamp,
                    department = department,
                    user = context.User.Id,
                    operation = context.Operation.Id,
                    requestPath = context.Request.Url.Path,
                    model = context.Request.Query.GetValueOrDefault("model", "unknown"),
                    status = "inbound"
                }.ToString();
            }

return-response.set-body:
@{
                        return JsonConvert.SerializeObject(new {
                            error = "Missing X-Department-Id header",
                            message = "All requests must include X-Department-Id header",
                            example = "X-Department-Id: data-science"
                        });
                    }

log-to-eventhub.expression:
@{
                return new {
                    timestamp = DateTime.UtcNow.ToString("o"),
                    department = context.Variables["department"],
                    user = context.User.Id,
                    tokens = {
                        prompt = context.Variables["prompt-tokens"],
                        completion = context.Variables["complete-tokens"],
                        total = context.Variables["total-tokens"]
                    },
                    model = context.Request.Query.GetValueOrDefault("model", "unknown"),
                    responseStatus = context.Response.StatusCode,
                    responseTime = context.Elapsed.TotalMilliseconds,
                    status = "outbound"
                }.ToString();
            }

@{
                return new {
                    timestamp = DateTime.UtcNow.ToString("o"),
                    department = context.Variables["department"],
                    error = context.LastError.Message,
                    status = "error"
                }.ToString();
            }
